  "type": "LEARNING_CARD",
  "title": "Choosing the Perfect Dress",
  "lessonText": "Selecting the right dress is crucial for a successful dance experience.",
  "data": {
    "learningCards": [
      {
        "title": "Consider the Dance Style",
        "content": "Different styles require different dress types. \n- Ballroom: Flowing gowns. \n- Salsa: Fitted dresses. \n- Hip Hop: Casual attire.",
        "layout": "bullet"
      },
      {
        "title": "Think About Comfort",
        "content": "You need to move freely. \n- Choose breathable fabrics. \n- Ensure a good fit.",
        "layout": "bullet"
      },
      {
        "title": "Color and Patterns",
        "content": "Select colors that suit your personality. \n- Bright colors for fun. \n- Dark colors for elegance.",
        "layout": "bullet"
      },
      {
        "title": "Accessorize Wisely",
        "content": "Accessories can enhance your look. \n- Choose simple jewelry. \n- Consider matching shoes.",
        "layout": "bullet"
      }
    ]
  }
}
